import { useEffect, useState, type FormEvent, type ReactNode } from 'react';
import { addDoc, collection, doc, onSnapshot, orderBy, query, serverTimestamp, updateDoc } from 'firebase/firestore';
import { Award, Bell, BookOpen, CalendarDays, ClipboardList, FileText, GraduationCap, MessageSquare, Plus, Search, Target, UserCheck, X } from 'lucide-react';
import { auth, db } from './firebase';
import { useAuth } from './AuthContext';
import type { StaffProfile } from './types';

const can=(a:any,p:string)=>Boolean(a?.systemRoles?.includes('SYSTEM_ADMINISTRATOR')||a?.permissions?.includes(p));
const date=(v:any)=>v?.toDate?.().toLocaleDateString()??'—';
function useDocs<T>(path:string){const [items,setItems]=useState<T[]>([]);useEffect(()=>onSnapshot(query(collection(db,path),orderBy('createdAt','desc')),s=>setItems(s.docs.map(d=>({id:d.id,...d.data()} as T)))),[path]);return items}
function Section({title,subtitle,action}:{title:string;subtitle:string;action?:ReactNode}){return <div className="section-title"><div><h2>{title}</h2><p>{subtitle}</p></div>{action}</div>}
function Status({value}:{value:string}){return <span className={`status ${value.toLowerCase()}`}>{value.replaceAll('_',' ')}</span>}
function Table({headers,rows}:{headers:string[];rows:ReactNode[][]}){return <div className="table-wrap"><table><thead><tr>{headers.map(h=><th key={h}>{h}</th>)}</tr></thead><tbody>{rows.length?rows.map((r,i)=><tr key={i}>{r.map((c,j)=><td key={j}>{c}</td>)}</tr>):<tr><td colSpan={headers.length}><div className="empty">No records yet.</div></td></tr>}</tbody></table></div>}
function Modal({title,onClose,children}:{title:string;onClose:()=>void;children:ReactNode}){return <div className="modal-backdrop" onMouseDown={onClose}><section className="modal" onMouseDown={e=>e.stopPropagation()}><div className="modal-head"><h2>{title}</h2><button className="icon" onClick={onClose}><X/></button></div>{children}</section></div>}
const staffFields=(staff:StaffProfile[])=><label>Staff member<select name="staffProfileId" required><option value="">Select</option>{staff.map(s=><option key={s.id} value={s.id}>{s.displayName}</option>)}</select></label>;

export default function PhaseFour(){const [tab,setTab]=useState('training');const tabs=[['training','Training',GraduationCap],['reviews','Reviews',ClipboardList],['goals','Goals',Target],['recognition','Recognition',Award],['leave','Leave',CalendarDays],['attendance','Attendance',UserCheck],['documents','Documents',BookOpen],['forms','Forms',FileText],['messages','Messages',MessageSquare],['notifications','Notifications',Bell]];return <section className="phase4"><Section title="Workforce Development & HR" subtitle="Training, performance, goals, recognition, leave, attendance, documents, forms, and communication"/><div className="tabs phase-tabs module-tabs">{tabs.map(([id,label,Icon]:any)=><button key={id} className={tab===id?'selected':''} onClick={()=>setTab(id)}><Icon/>{label}</button>)}</div>{tab==='training'&&<Training/>}{tab==='reviews'&&<Reviews/>}{tab==='goals'&&<Goals/>}{tab==='recognition'&&<Recognition/>}{tab==='leave'&&<Leave/>}{tab==='attendance'&&<Attendance/>}{tab==='documents'&&<Documents/>}{tab==='forms'&&<Forms/>}{tab==='messages'&&<Messages/>}{tab==='notifications'&&<Notifications/>}</section>}

function Training(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const courses=useDocs<any>('courses');const assignments=useDocs<any>('courseAssignments');const certs=useDocs<any>('certifications');const [mode,setMode]=useState('');async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);if(mode==='course')await addDoc(collection(db,'courses'),{title:String(f.get('title')),description:String(f.get('description')),passingScore:Number(f.get('passingScore')),monthly:f.get('monthly')==='on',status:'PUBLISHED',createdBy:auth.currentUser?.uid,createdAt:serverTimestamp()});if(mode==='assign'){const s=staff.find(x=>x.id===f.get('staffProfileId'));const c=courses.find(x=>x.id===f.get('courseId'));if(s&&c)await addDoc(collection(db,'courseAssignments'),{staffProfileId:s.id,staffName:s.displayName,courseId:c.id,courseTitle:c.title,status:'ASSIGNED',progress:0,dueDate:String(f.get('dueDate')),assignedBy:auth.currentUser?.uid,createdAt:serverTimestamp()})}if(mode==='cert'){const s=staff.find(x=>x.id===f.get('staffProfileId'));if(s)await addDoc(collection(db,'certifications'),{staffProfileId:s.id,staffName:s.displayName,name:String(f.get('name')),certificateNumber:String(f.get('certificateNumber')),issuedDate:String(f.get('issuedDate')),expiresDate:String(f.get('expiresDate')),status:'ACTIVE',createdBy:auth.currentUser?.uid,createdAt:serverTimestamp()})}setMode('')}
return <><Section title="Training Center" subtitle="Courses, monthly requirements, assignments, progress, quizzes, certificates, and renewals" action={can(account,'training.manage')?<span className="actions"><button onClick={()=>setMode('course')}><Plus/>Course</button><button onClick={()=>setMode('assign')}><Plus/>Assign</button><button onClick={()=>setMode('cert')}><Plus/>Certification</button></span>:undefined}/><div className="grid"><article className="card"><p>Published Courses</p><strong>{courses.length}</strong><span>{courses.filter(x=>x.monthly).length} recurring monthly</span></article><article className="card"><p>Open Assignments</p><strong>{assignments.filter(x=>x.status!=='COMPLETED').length}</strong><span>Training still in progress</span></article><article className="card"><p>Active Certifications</p><strong>{certs.filter(x=>x.status==='ACTIVE').length}</strong><span>Renewal tracking enabled</span></article></div><Section title="Assignments" subtitle="Individual progress and deadlines"/><Table headers={['Staff','Course','Progress','Due','Status','Update']} rows={assignments.map(a=>[a.staffName,a.courseTitle,`${a.progress||0}%`,a.dueDate||'—',<Status value={a.status}/>,can(account,'training.grade')?<button className="small" onClick={()=>updateDoc(doc(db,'courseAssignments',a.id),{status:'COMPLETED',progress:100,completedAt:serverTimestamp()})}>Complete</button>:'—'])}/>{mode&&<Modal title={mode==='course'?'Create course':mode==='assign'?'Assign training':'Issue certification'} onClose={()=>setMode('')}><form onSubmit={submit} className="form-grid">{mode==='course'&&<><label>Course title<input name="title" required/></label><label>Passing score<input name="passingScore" type="number" min="0" max="100" defaultValue="80"/></label><label className="check"><input name="monthly" type="checkbox"/>Required monthly</label><label className="wide">Description<textarea name="description" rows={5}/></label></>}{mode==='assign'&&<>{staffFields(staff)}<label>Course<select name="courseId" required><option value="">Select</option>{courses.map(c=><option key={c.id} value={c.id}>{c.title}</option>)}</select></label><label>Due date<input name="dueDate" type="date" required/></label></>}{mode==='cert'&&<>{staffFields(staff)}<label>Certification<input name="name" required/></label><label>Certificate number<input name="certificateNumber" required/></label><label>Issue date<input name="issuedDate" type="date" required/></label><label>Expiration date<input name="expiresDate" type="date"/></label></>}<button className="wide">Save</button></form></Modal>}</>}

function Reviews(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const items=useDocs<any>('performanceReviews');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const s=staff.find(x=>x.id===f.get('staffProfileId'));if(!s)return;const scores=['professionalism','activity','leadership','attendance','communication','knowledge','initiative'].map(k=>Number(f.get(k)));await addDoc(collection(db,'performanceReviews'),{staffProfileId:s.id,staffName:s.displayName,reviewType:String(f.get('reviewType')),scores,overallScore:Math.round(scores.reduce((a,b)=>a+b,0)/scores.length),comments:String(f.get('comments')),status:'SUPERVISOR_REVIEW',createdBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Performance Reviews" subtitle="30-day, 90-day, quarterly, annual, and custom evaluations" action={can(account,'reviews.submit')?<button onClick={()=>setShow(true)}><Plus/>New review</button>:undefined}/><Table headers={['Employee','Type','Score','Status','Created','Approve']} rows={items.map(r=>[r.staffName,r.reviewType,`${r.overallScore}%`,<Status value={r.status}/>,date(r.createdAt),can(account,'reviews.approve')&&r.status!=='ACKNOWLEDGED'?<button className="small" onClick={()=>updateDoc(doc(db,'performanceReviews',r.id),{status:'APPROVED',approvedBy:auth.currentUser?.uid,approvedAt:serverTimestamp()})}>Approve</button>:'—'])}/>{show&&<Modal title="Create performance review" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid">{staffFields(staff)}<label>Review type<select name="reviewType"><option>30_DAY</option><option>90_DAY</option><option>QUARTERLY</option><option>ANNUAL</option><option>CUSTOM</option></select></label>{['professionalism','activity','leadership','attendance','communication','knowledge','initiative'].map(k=><label key={k}>{k[0].toUpperCase()+k.slice(1)}<input name={k} type="number" min="0" max="100" required/></label>)}<label className="wide">Comments<textarea name="comments" rows={5}/></label><button className="wide">Submit review</button></form></Modal>}</>}

function Goals(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const items=useDocs<any>('goalAssignments');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const s=staff.find(x=>x.id===f.get('staffProfileId'));if(!s)return;await addDoc(collection(db,'goalAssignments'),{staffProfileId:s.id,staffName:s.displayName,title:String(f.get('title')),description:String(f.get('description')),target:Number(f.get('target')),progress:0,dueDate:String(f.get('dueDate')),status:'ACTIVE',assignedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Goals" subtitle="Assign measurable development and performance goals" action={can(account,'goals.manage')?<button onClick={()=>setShow(true)}><Plus/>Assign goal</button>:undefined}/><div className="progress-grid">{items.map(g=>{const pct=Math.min(100,Math.round((g.progress||0)/(g.target||1)*100));return <article className="progress-card" key={g.id}><div><strong>{g.staffName}: {g.title}</strong><span>{g.progress||0}/{g.target}</span></div><div className="progress"><i style={{width:`${pct}%`}}/></div><small>Due {g.dueDate||'—'} · {g.status}</small>{can(account,'goals.manage')&&<button className="small" onClick={()=>updateDoc(doc(db,'goalAssignments',g.id),{progress:Math.min(g.target,(g.progress||0)+1),updatedAt:serverTimestamp()})}>Add progress</button>}</article>})}</div>{show&&<Modal title="Assign goal" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid">{staffFields(staff)}<label>Goal title<input name="title" required/></label><label>Target<input name="target" type="number" min="1" required/></label><label>Deadline<input name="dueDate" type="date" required/></label><label className="wide">Description<textarea name="description" rows={4}/></label><button className="wide">Assign</button></form></Modal>}</>}

function Recognition(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const items=useDocs<any>('recognitions');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const s=staff.find(x=>x.id===f.get('staffProfileId'));if(!s)return;await addDoc(collection(db,'recognitions'),{staffProfileId:s.id,staffName:s.displayName,title:String(f.get('title')),description:String(f.get('description')),awardedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Recognition" subtitle="Badges, commendations, and employee awards" action={can(account,'recognitions.manage')?<button onClick={()=>setShow(true)}><Plus/>Give award</button>:undefined}/><div className="department-grid">{items.map(x=><article className="card award-card" key={x.id}><Award/><p>{date(x.createdAt)}</p><strong>{x.title}</strong><span>{x.staffName}</span><small>{x.description}</small></article>)}</div>{show&&<Modal title="Award recognition" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid">{staffFields(staff)}<label>Award title<input name="title" required/></label><label className="wide">Description<textarea name="description" rows={4}/></label><button className="wide">Award</button></form></Modal>}</>}

function Leave(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const items=useDocs<any>('leaveRequests');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const s=staff.find(x=>x.id===f.get('staffProfileId'));if(!s)return;await addDoc(collection(db,'leaveRequests'),{staffProfileId:s.id,staffName:s.displayName,type:String(f.get('type')),startDate:String(f.get('startDate')),endDate:String(f.get('endDate')),reason:String(f.get('reason')),status:'PENDING',submittedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Leave Management" subtitle="Vacation, personal, medical, educational, and other leave" action={<button onClick={()=>setShow(true)}><Plus/>Request leave</button>}/><Table headers={['Employee','Type','Dates','Reason','Status','Decision']} rows={items.map(x=>[x.staffName,x.type,`${x.startDate} – ${x.endDate}`,x.reason,<Status value={x.status}/>,can(account,'leave.approve')&&x.status==='PENDING'?<span className="actions"><button className="small" onClick={()=>updateDoc(doc(db,'leaveRequests',x.id),{status:'APPROVED',reviewedBy:auth.currentUser?.uid,reviewedAt:serverTimestamp()})}>Approve</button><button className="small danger" onClick={()=>updateDoc(doc(db,'leaveRequests',x.id),{status:'DENIED',reviewedBy:auth.currentUser?.uid,reviewedAt:serverTimestamp()})}>Deny</button></span>:'—'])}/>{show&&<Modal title="Submit leave request" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid">{staffFields(staff)}<label>Leave type<select name="type"><option>VACATION</option><option>PERSONAL</option><option>MEDICAL</option><option>EDUCATIONAL</option><option>MILITARY</option></select></label><label>Start<input name="startDate" type="date" required/></label><label>End<input name="endDate" type="date" required/></label><label className="wide">Reason<textarea name="reason" rows={4} required/></label><button className="wide">Submit</button></form></Modal>}</>}

function Attendance(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles');const items=useDocs<any>('attendanceRecords');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const s=staff.find(x=>x.id===f.get('staffProfileId'));if(!s)return;await addDoc(collection(db,'attendanceRecords'),{staffProfileId:s.id,staffName:s.displayName,eventTitle:String(f.get('eventTitle')),eventType:String(f.get('eventType')),attendanceStatus:String(f.get('attendanceStatus')),eventDate:String(f.get('eventDate')),recordedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Attendance" subtitle="Meetings, trainings, events, and roll calls" action={can(account,'attendance.manage')?<button onClick={()=>setShow(true)}><Plus/>Record attendance</button>:undefined}/><Table headers={['Employee','Event','Type','Date','Attendance']} rows={items.map(x=>[x.staffName,x.eventTitle,x.eventType,x.eventDate,<Status value={x.attendanceStatus}/>])}/>{show&&<Modal title="Record attendance" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid">{staffFields(staff)}<label>Event title<input name="eventTitle" required/></label><label>Event type<select name="eventType"><option>MEETING</option><option>TRAINING</option><option>EVENT</option><option>ROLL_CALL</option></select></label><label>Status<select name="attendanceStatus"><option>PRESENT</option><option>LATE</option><option>EXCUSED</option><option>ABSENT</option></select></label><label>Date<input name="eventDate" type="date" required/></label><button className="wide">Save</button></form></Modal>}</>}

function Documents(){const {account}=useAuth();const items=useDocs<any>('documents');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await addDoc(collection(db,'documents'),{title:String(f.get('title')),category:String(f.get('category')),version:String(f.get('version')),url:String(f.get('url')),visibility:String(f.get('visibility')),status:'PUBLISHED',createdBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Document Library" subtitle="Policies, handbooks, SOPs, guides, manuals, and version history" action={can(account,'documents.manage')?<button onClick={()=>setShow(true)}><Plus/>Add document</button>:undefined}/><div className="document-grid">{items.map(x=><a className="document-card" href={x.url} target="_blank" rel="noreferrer" key={x.id}><FileText/><div><strong>{x.title}</strong><span>{x.category} · v{x.version}</span><small>{x.visibility} · {date(x.createdAt)}</small></div></a>)}</div>{show&&<Modal title="Publish document" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Title<input name="title" required/></label><label>Category<input name="category" required/></label><label>Version<input name="version" defaultValue="1.0" required/></label><label>Visibility<select name="visibility"><option>ALL_STAFF</option><option>LEADERSHIP</option><option>EXECUTIVE</option></select></label><label className="wide">Document link<input name="url" type="url" required/></label><button className="wide">Publish</button></form></Modal>}</>}

function Forms(){const {account}=useAuth();const items=useDocs<any>('formResponses');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await addDoc(collection(db,'formResponses'),{formType:String(f.get('formType')),subject:String(f.get('subject')),response:String(f.get('response')),status:'SUBMITTED',submittedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <><Section title="Digital Forms" subtitle="Incident reports, complaints, suggestions, transfers, resignations, and exit interviews" action={<button onClick={()=>setShow(true)}><Plus/>New form</button>}/><Table headers={['Type','Subject','Status','Submitted','Review']} rows={items.map(x=>[x.formType,x.subject,<Status value={x.status}/>,date(x.createdAt),can(account,'forms.manage')?<button className="small" onClick={()=>updateDoc(doc(db,'formResponses',x.id),{status:'REVIEWED',reviewedBy:auth.currentUser?.uid,reviewedAt:serverTimestamp()})}>Mark reviewed</button>:'—'])}/>{show&&<Modal title="Submit internal form" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Form type<select name="formType"><option>INCIDENT_REPORT</option><option>COMPLAINT</option><option>SUGGESTION</option><option>TRANSFER_REQUEST</option><option>RESIGNATION</option><option>EXIT_INTERVIEW</option></select></label><label>Subject<input name="subject" required/></label><label className="wide">Response<textarea name="response" rows={7} required/></label><button className="wide">Submit</button></form></Modal>}</>}

function Messages(){const {account}=useAuth();const items=useDocs<any>('internalMessages');const [show,setShow]=useState(false);const [search,setSearch]=useState('');async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await addDoc(collection(db,'internalMessages'),{channel:String(f.get('channel')),recipient:String(f.get('recipient')),subject:String(f.get('subject')),body:String(f.get('body')),priority:String(f.get('priority')),pinned:false,readBy:[],sentBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}const filtered=items.filter(x=>`${x.subject} ${x.body} ${x.channel}`.toLowerCase().includes(search.toLowerCase()));return <><Section title="Internal Messaging" subtitle="Direct, department, organization, pinned, and priority messages" action={<button onClick={()=>setShow(true)}><Plus/>New message</button>}/><label className="search"><Search/><input placeholder="Search messages" value={search} onChange={e=>setSearch(e.target.value)}/></label><div className="announcement-list">{filtered.map(x=><article className={`announcement ${String(x.priority).toLowerCase()}`} key={x.id}><div><span className="badge">{x.channel}</span><small>{date(x.createdAt)}</small></div><h2>{x.subject}</h2><p>{x.body}</p>{can(account,'messages.manage')&&<button className="small ghost-inline" onClick={()=>updateDoc(doc(db,'internalMessages',x.id),{pinned:!x.pinned})}>{x.pinned?'Unpin':'Pin'}</button>}</article>)}</div>{show&&<Modal title="Send internal message" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Channel<select name="channel"><option>DIRECT</option><option>DEPARTMENT</option><option>ALL_STAFF</option><option>LEADERSHIP</option></select></label><label>Recipient / audience<input name="recipient" required/></label><label>Priority<select name="priority"><option>NORMAL</option><option>IMPORTANT</option><option>URGENT</option></select></label><label className="wide">Subject<input name="subject" required/></label><label className="wide">Message<textarea name="body" rows={7} required/></label><button className="wide">Send</button></form></Modal>}</>}

function Notifications(){const items=useDocs<any>('notifications');return <><Section title="Notification Center" subtitle="Approvals, training, quota, promotion, policy, leave, and security notices"/><div className="notification-list">{items.map(x=><article className={x.read?'notification read':'notification'} key={x.id}><Bell/><div><strong>{x.title}</strong><p>{x.body}</p><small>{date(x.createdAt)}</small></div>{!x.read&&<button className="small" onClick={()=>updateDoc(doc(db,'notifications',x.id),{read:true,readAt:serverTimestamp()})}>Mark read</button>}</article>)}</div></>}
