import { useEffect, useMemo, useState, type FormEvent, type ReactNode } from 'react';
import { Navigate, NavLink, Route, Routes, Link, useNavigate } from 'react-router-dom';
import { signInAnonymously, linkWithCredential, EmailAuthProvider, deleteUser } from 'firebase/auth';
import { addDoc, collection, doc, getDoc, onSnapshot, orderBy, query, runTransaction, serverTimestamp, updateDoc, type QueryConstraint } from 'firebase/firestore';
import { auth, db } from './firebase';
import { aliasFor, useAuth } from './AuthContext';
import type { Announcement, Department, PersonnelAction, QuotaSubmission, Rank, StaffProfile } from './types';
import { ShieldCheck, KeyRound, LayoutDashboard, Users, Settings, LogOut, Building2, ClipboardCheck, Megaphone, Plus, Search, ArrowRightLeft, Menu, X } from 'lucide-react';

const codeHash=async(s:string)=>Array.from(new Uint8Array(await crypto.subtle.digest('SHA-256',new TextEncoder().encode(s.trim().toUpperCase())))).map(b=>b.toString(16).padStart(2,'0')).join('');
const date=(v:any)=>v?.toDate?.().toLocaleDateString()??'—';
const can=(account:any,p:string)=>Boolean(account?.systemRoles?.includes('SYSTEM_ADMINISTRATOR')||account?.permissions?.includes(p));

function useDocs<T>(path:string,constraints:QueryConstraint[]=[]){const [items,setItems]=useState<T[]>([]);useEffect(()=>onSnapshot(query(collection(db,path),...constraints),s=>setItems(s.docs.map(d=>({id:d.id,...d.data()} as T)))),[path]);return items}
function Status({value}:{value:string}){return <span className={`status ${value.toLowerCase()}`}>{value.replaceAll('_',' ')}</span>}
function Section({title,subtitle,action}:{title:string;subtitle:string;action?:ReactNode}){return <div className="section-title"><div><h2>{title}</h2><p>{subtitle}</p></div>{action}</div>}
function Card({title,value,text}:{title:string;value:string;text:string}){return <article className="card"><p>{title}</p><strong>{value}</strong><span>{text}</span></article>}
function Table({headers,rows}:{headers:string[];rows:ReactNode[][]}){return <div className="table-wrap"><table><thead><tr>{headers.map(h=><th key={h}>{h}</th>)}</tr></thead><tbody>{rows.length?rows.map((r,i)=><tr key={i}>{r.map((c,j)=><td key={j}>{c}</td>)}</tr>):<tr><td colSpan={headers.length}><div className="empty">No records yet.</div></td></tr>}</tbody></table></div>}
function Modal({title,onClose,children}:{title:string;onClose:()=>void;children:ReactNode}){return <div className="modal-backdrop" onMouseDown={onClose}><section className="modal" onMouseDown={e=>e.stopPropagation()}><div className="modal-head"><h2>{title}</h2><button className="icon" onClick={onClose}><X/></button></div>{children}</section></div>}

function AuthCard({title,subtitle,children}:{title:string;subtitle:string;children:ReactNode}){return <main className="auth"><section className="auth-card"><div className="brand-mark"><ShieldCheck/></div><p className="eyebrow">CANELA CORPORATION</p><h1>{title}</h1><p className="muted">{subtitle}</p>{children}</section></main>}
function Login(){const {login}=useAuth();const nav=useNavigate();const [u,setU]=useState('');const [p,setP]=useState('');const [error,setError]=useState('');return <AuthCard title="Welcome back" subtitle="Sign in with your Canela portal credentials."><form onSubmit={async e=>{e.preventDefault();try{await login(u,p);nav('/dashboard')}catch{setError('Invalid username or password.')}}}><label>Username<input value={u} onChange={e=>setU(e.target.value)} required/></label><label>Password<input type="password" value={p} onChange={e=>setP(e.target.value)} minLength={10} required/></label>{error&&<p className="error">{error}</p>}<button>Sign in</button></form><p className="muted">Have an activation code? <Link to="/activate">Activate account</Link></p></AuthCard>}
function Activate(){const nav=useNavigate();const [code,setCode]=useState('');const [username,setUsername]=useState('');const [password,setPassword]=useState('');const [error,setError]=useState('');return <AuthCard title="Activate your account" subtitle="Use the one-time code provided by an authorized administrator."><form onSubmit={async e=>{e.preventDefault();let temporary=false;try{await signInAnonymously(auth);temporary=true;const hash=await codeHash(code);const ref=doc(db,'activationCodes',hash);const preview=await getDoc(ref);if(!preview.exists()||preview.data().status!=='PENDING'||preview.data().expiresAt?.toMillis()<Date.now())throw new Error('This activation code is invalid or expired.');if(!auth.currentUser)throw new Error('Activation failed.');await linkWithCredential(auth.currentUser,EmailAuthProvider.credential(aliasFor(username),password));const uid=auth.currentUser.uid;await runTransaction(db,async tx=>{const fresh=await tx.get(ref);if(!fresh.exists()||fresh.data().status!=='PENDING')throw new Error('This code has already been used.');const c=fresh.data();tx.set(doc(db,'portalAccounts',uid),{displayName:c.displayName,portalUsername:username.trim().toLowerCase(),organizationalRank:c.organizationalRank??'Staff',portalStatus:'ACTIVE',systemRoles:[],permissions:c.permissions??[],staffProfileId:c.staffProfileId,activationCodeHash:hash,createdAt:serverTimestamp(),lastLoginAt:serverTimestamp()});tx.set(doc(db,'portalUsernames',username.trim().toLowerCase()),{uid,createdAt:serverTimestamp()});tx.update(ref,{status:'USED',usedByUid:uid,usedAt:serverTimestamp()});tx.set(doc(db,'auditLogs',crypto.randomUUID()),{action:'ACCOUNT_ACTIVATED',actorUid:uid,targetUid:uid,createdAt:serverTimestamp()})});nav('/dashboard')}catch(err){if(temporary&&auth.currentUser)await deleteUser(auth.currentUser).catch(()=>{});setError(err instanceof Error?err.message:'Activation failed.')}}}><label>Activation code<input value={code} onChange={e=>setCode(e.target.value)} required/></label><label>Choose username<input value={username} onChange={e=>setUsername(e.target.value)} pattern="[A-Za-z0-9._-]{4,24}" required/></label><label>Choose password<input type="password" value={password} onChange={e=>setPassword(e.target.value)} minLength={10} required/></label>{error&&<p className="error">{error}</p>}<button>Activate account</button></form><p className="muted"><Link to="/login">Return to sign in</Link></p></AuthCard>}

function Shell(){const {account,logout}=useAuth();const [open,setOpen]=useState(false);return <div className="shell"><aside className={open?'open':''}><div className="logo"><ShieldCheck/><span>CANELA</span><button className="mobile-close" onClick={()=>setOpen(false)}><X/></button></div><nav onClick={()=>setOpen(false)}><NavLink to="/dashboard"><LayoutDashboard/>Dashboard</NavLink><NavLink to="/staff"><Users/>Staff Directory</NavLink><NavLink to="/organization"><Building2/>Organization</NavLink><NavLink to="/personnel"><ArrowRightLeft/>Personnel</NavLink><NavLink to="/quotas"><ClipboardCheck/>Quotas</NavLink><NavLink to="/announcements"><Megaphone/>Announcements</NavLink>{account?.systemRoles?.includes('SYSTEM_ADMINISTRATOR')&&<NavLink to="/admin"><Settings/>System Admin</NavLink>}</nav><button className="ghost" onClick={logout}><LogOut/>Sign out</button></aside><main className="content"><header><button className="mobile-menu" onClick={()=>setOpen(true)}><Menu/></button><div><p className="eyebrow">ADMINISTRATION PORTAL</p><h1>Welcome, {account?.displayName}</h1></div><span className="pill">{account?.organizationalRank}</span></header><Routes><Route path="dashboard" element={<Dashboard/>}/><Route path="staff" element={<Staff/>}/><Route path="organization" element={<Organization/>}/><Route path="personnel" element={<Personnel/>}/><Route path="quotas" element={<Quotas/>}/><Route path="announcements" element={<Announcements/>}/><Route path="admin" element={<Admin/>}/><Route path="*" element={<Navigate to="dashboard"/>}/></Routes></main></div>}

function Dashboard(){const staff=useDocs<StaffProfile>('staffProfiles');const actions=useDocs<PersonnelAction>('personnelActions',[orderBy('createdAt','desc')]);const quotas=useDocs<QuotaSubmission>('quotaSubmissions',[orderBy('createdAt','desc')]);const announcements=useDocs<Announcement>('announcements',[orderBy('createdAt','desc')]);const pending=actions.filter(x=>x.status==='PENDING').length+quotas.filter(x=>x.status==='PENDING').length;return <><section className="hero"><div><p className="eyebrow">PHASE TWO</p><h2>Personnel operations in one connected workspace.</h2><p>Manage staff, hierarchy, promotions, transfers, quotas, leave, resignations, and organization-wide announcements.</p></div><ShieldCheck/></section><div className="grid"><Card title="Active Staff" value={String(staff.filter(x=>x.status==='ACTIVE').length)} text={`${staff.length} total profiles`}/><Card title="Pending Reviews" value={String(pending)} text="Personnel and quota requests"/><Card title="Announcements" value={String(announcements.filter(x=>x.published).length)} text="Currently published"/></div><Section title="Recent personnel activity" subtitle="Latest requests and organizational changes"/><Table headers={['Staff','Action','Change','Status']} rows={actions.slice(0,6).map(a=>[a.staffName,a.type,`${a.fromValue||'—'} → ${a.toValue||'—'}`,<Status value={a.status}/>])}/></>}

function Staff(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles',[orderBy('displayName')]);const ranks=useDocs<Rank>('ranks',[orderBy('order')]);const departments=useDocs<Department>('departments',[orderBy('name')]);const [search,setSearch]=useState('');const [show,setShow]=useState(false);const filtered=useMemo(()=>staff.filter(s=>`${s.displayName} ${s.robloxUsername} ${s.robloxUserId} ${s.discordUsername} ${s.discordId}`.toLowerCase().includes(search.toLowerCase())),[staff,search]);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await addDoc(collection(db,'staffProfiles'),{displayName:String(f.get('displayName')).trim(),robloxUsername:String(f.get('robloxUsername')).trim(),robloxUserId:String(f.get('robloxUserId')).trim(),discordUsername:String(f.get('discordUsername')).trim(),discordId:String(f.get('discordId')).trim(),rankId:String(f.get('rankId')),departmentId:String(f.get('departmentId')),status:'ACTIVE',quotaPoints:0,quotaTarget:Number(f.get('quotaTarget')||0),createdAt:serverTimestamp(),updatedAt:serverTimestamp(),createdBy:auth.currentUser?.uid});setShow(false)}return <section><Section title="Staff Directory" subtitle="One profile for every Canela staff member" action={can(account,'staff.manage')?<button onClick={()=>setShow(true)}><Plus/>Add staff member</button>:undefined}/><div className="toolbar"><label className="search"><Search/><input placeholder="Search Roblox, Discord, ID, or name" value={search} onChange={e=>setSearch(e.target.value)}/></label><span>{filtered.length} records</span></div><div className="staff-grid">{filtered.map(s=>{const rank=ranks.find(r=>r.id===s.rankId)?.name||s.rankId||'Unassigned';const dept=departments.find(d=>d.id===s.departmentId)?.name||s.departmentId||'Unassigned';return <article className="staff-card" key={s.id}><div className="avatar">{s.displayName.slice(0,2).toUpperCase()}</div><div><h3>{s.displayName}</h3><p>@{s.robloxUsername}</p></div><Status value={s.status}/><dl><div><dt>Rank</dt><dd>{rank}</dd></div><div><dt>Department</dt><dd>{dept}</dd></div><div><dt>Discord</dt><dd>{s.discordUsername||'—'}</dd></div><div><dt>Quota</dt><dd>{s.quotaPoints??0} / {s.quotaTarget??0}</dd></div></dl>{can(account,'staff.manage')&&<select value={s.status} onChange={e=>updateDoc(doc(db,'staffProfiles',s.id),{status:e.target.value,updatedAt:serverTimestamp()})}>{['ACTIVE','LEAVE_OF_ABSENCE','SUSPENDED','RESIGNED','TERMINATED','FORMER_STAFF'].map(x=><option key={x}>{x}</option>)}</select>}</article>})}</div>{show&&<Modal title="Create staff profile" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Display name<input name="displayName" required/></label><label>Roblox username<input name="robloxUsername" required/></label><label>Roblox User ID<input name="robloxUserId" required/></label><label>Discord username<input name="discordUsername" required/></label><label>Discord ID<input name="discordId" required/></label><label>Rank<select name="rankId" required><option value="">Select rank</option>{ranks.map(r=><option value={r.id} key={r.id}>{r.name}</option>)}</select></label><label>Department<select name="departmentId" required><option value="">Select department</option>{departments.map(d=><option value={d.id} key={d.id}>{d.name}</option>)}</select></label><label>Quota target<input name="quotaTarget" type="number" min="0" defaultValue="0"/></label><button className="wide">Create profile</button></form></Modal>}</section>}

function Organization(){const {account}=useAuth();const ranks=useDocs<Rank>('ranks',[orderBy('order')]);const departments=useDocs<Department>('departments',[orderBy('name')]);const staff=useDocs<StaffProfile>('staffProfiles');const [tab,setTab]=useState<'ranks'|'departments'>('ranks');const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);if(tab==='ranks')await addDoc(collection(db,'ranks'),{name:String(f.get('name')).trim(),abbreviation:String(f.get('abbreviation')).trim(),tier:String(f.get('tier')).trim(),order:Number(f.get('order')),limit:Number(f.get('limit')||0),quotaTarget:Number(f.get('quotaTarget')||0),description:String(f.get('description')||'').trim(),createdAt:serverTimestamp()});else await addDoc(collection(db,'departments'),{name:String(f.get('name')).trim(),abbreviation:String(f.get('abbreviation')).trim(),description:String(f.get('description')||'').trim(),active:true,createdAt:serverTimestamp()});setShow(false)}return <section><Section title="Organization" subtitle="Ranks, tiers, limits, departments, and structure" action={can(account,'organization.manage')?<button onClick={()=>setShow(true)}><Plus/>Add {tab==='ranks'?'rank':'department'}</button>:undefined}/><div className="tabs"><button className={tab==='ranks'?'selected':''} onClick={()=>setTab('ranks')}>Ranks</button><button className={tab==='departments'?'selected':''} onClick={()=>setTab('departments')}>Departments</button></div>{tab==='ranks'?<Table headers={['Order','Rank','Tier','Occupancy','Quota']} rows={ranks.map(r=>[r.order,`${r.name} (${r.abbreviation})`,r.tier,`${staff.filter(s=>s.rankId===r.id&&s.status==='ACTIVE').length} / ${r.limit||'∞'}`,r.quotaTarget??0])}/>:<div className="department-grid">{departments.map(d=><article className="card" key={d.id}><p>{d.abbreviation}</p><strong>{d.name}</strong><span>{staff.filter(s=>s.departmentId===d.id&&s.status==='ACTIVE').length} active members</span><small>{d.description}</small></article>)}</div>}{show&&<Modal title={`Add ${tab==='ranks'?'rank':'department'}`} onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Name<input name="name" required/></label><label>Abbreviation<input name="abbreviation" required/></label>{tab==='ranks'&&<><label>Tier<input name="tier" required/></label><label>Hierarchy order<input name="order" type="number" required/></label><label>Rank limit<input name="limit" type="number" min="0"/></label><label>Quota target<input name="quotaTarget" type="number" min="0"/></label></>}<label className="wide">Description<textarea name="description" rows={4}/></label><button className="wide">Save</button></form></Modal>}</section>}

function Personnel(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles',[orderBy('displayName')]);const ranks=useDocs<Rank>('ranks',[orderBy('order')]);const departments=useDocs<Department>('departments',[orderBy('name')]);const actions=useDocs<PersonnelAction>('personnelActions',[orderBy('createdAt','desc')]);const [show,setShow]=useState(false);const label=(id?:string)=>ranks.find(r=>r.id===id)?.name||departments.find(d=>d.id===id)?.name||id||'—';async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const member=staff.find(s=>s.id===f.get('staffProfileId'));if(!member)return;await addDoc(collection(db,'personnelActions'),{staffProfileId:member.id,staffName:member.displayName,type:String(f.get('type')),fromValue:String(f.get('fromValue')||''),toValue:String(f.get('toValue')||''),reason:String(f.get('reason')).trim(),status:'PENDING',requestedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}async function decide(a:PersonnelAction,status:'APPROVED'|'DENIED'){await runTransaction(db,async tx=>{tx.update(doc(db,'personnelActions',a.id),{status,approvedBy:auth.currentUser?.uid,effectiveAt:serverTimestamp()});if(status==='APPROVED'){const patch:any={updatedAt:serverTimestamp()};if(a.type==='PROMOTION'||a.type==='DEMOTION')patch.rankId=a.toValue;if(a.type==='TRANSFER')patch.departmentId=a.toValue;if(a.type==='RESIGNATION')patch.status='RESIGNED';if(a.type==='TERMINATION')patch.status='TERMINATED';if(a.type==='STATUS_CHANGE')patch.status=a.toValue;tx.update(doc(db,'staffProfiles',a.staffProfileId),patch)}tx.set(doc(db,'auditLogs',crypto.randomUUID()),{action:`PERSONNEL_${status}`,actorUid:auth.currentUser?.uid,targetId:a.id,createdAt:serverTimestamp()})})}return <section><Section title="Personnel Operations" subtitle="Promotions, demotions, transfers, leave, resignations, and terminations" action={<button onClick={()=>setShow(true)}><Plus/>New request</button>}/><Table headers={['Staff','Type','Change','Reason','Requested','Status','Review']} rows={actions.map(a=>[a.staffName,a.type,`${label(a.fromValue)} → ${label(a.toValue)}`,a.reason,date(a.createdAt),<Status value={a.status}/>,can(account,'personnel.approve')&&a.status==='PENDING'?<span className="actions"><button className="small" onClick={()=>decide(a,'APPROVED')}>Approve</button><button className="small danger" onClick={()=>decide(a,'DENIED')}>Deny</button></span>:'—'])}/>{show&&<Modal title="New personnel request" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Staff member<select name="staffProfileId" required><option value="">Select</option>{staff.map(s=><option value={s.id} key={s.id}>{s.displayName}</option>)}</select></label><label>Action<select name="type">{['PROMOTION','DEMOTION','TRANSFER','STATUS_CHANGE','RESIGNATION','TERMINATION'].map(x=><option key={x}>{x}</option>)}</select></label><label>Current value<select name="fromValue"><option value="">None</option>{ranks.map(r=><option value={r.id} key={r.id}>{r.name}</option>)}{departments.map(d=><option value={d.id} key={d.id}>{d.name}</option>)}</select></label><label>New value<select name="toValue"><option value="">None</option>{ranks.map(r=><option value={r.id} key={r.id}>{r.name}</option>)}{departments.map(d=><option value={d.id} key={d.id}>{d.name}</option>)}{['ACTIVE','LEAVE_OF_ABSENCE','SUSPENDED'].map(x=><option key={x}>{x}</option>)}</select></label><label className="wide">Reason<textarea name="reason" rows={4} required/></label><button className="wide">Submit for review</button></form></Modal>}</section>}

function Quotas(){const {account}=useAuth();const staff=useDocs<StaffProfile>('staffProfiles',[orderBy('displayName')]);const submissions=useDocs<QuotaSubmission>('quotaSubmissions',[orderBy('createdAt','desc')]);const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const member=staff.find(s=>s.id===f.get('staffProfileId'));if(!member)return;await addDoc(collection(db,'quotaSubmissions'),{staffProfileId:member.id,staffName:member.displayName,activityType:String(f.get('activityType')).trim(),points:Number(f.get('points')),description:String(f.get('description')).trim(),evidenceUrl:String(f.get('evidenceUrl')||'').trim(),status:'PENDING',submittedBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}async function decide(q:QuotaSubmission,status:'APPROVED'|'DENIED'){await runTransaction(db,async tx=>{tx.update(doc(db,'quotaSubmissions',q.id),{status,reviewedBy:auth.currentUser?.uid,reviewedAt:serverTimestamp()});if(status==='APPROVED'){const ref=doc(db,'staffProfiles',q.staffProfileId);const snap=await tx.get(ref);tx.update(ref,{quotaPoints:Number(snap.data()?.quotaPoints??0)+q.points,updatedAt:serverTimestamp()})}})}return <section><Section title="Quota Management" subtitle="Submit, review, and track staff activity" action={<button onClick={()=>setShow(true)}><Plus/>Submit activity</button>}/><div className="progress-grid">{staff.filter(s=>s.status==='ACTIVE').slice(0,8).map(s=>{const target=s.quotaTarget||1;const pct=Math.min(100,Math.round(((s.quotaPoints||0)/target)*100));return <article className="progress-card" key={s.id}><div><strong>{s.displayName}</strong><span>{s.quotaPoints||0} / {s.quotaTarget||0} points</span></div><div className="progress"><i style={{width:`${pct}%`}}/></div><small>{pct>=100?'Completed':pct>=70?'On track':'At risk'}</small></article>})}</div><Section title="Submissions" subtitle="Activity evidence awaiting review"/><Table headers={['Staff','Activity','Points','Evidence','Date','Status','Review']} rows={submissions.map(q=>[q.staffName,q.activityType,q.points,q.evidenceUrl?<a href={q.evidenceUrl} target="_blank" rel="noreferrer">Open link</a>:'—',date(q.createdAt),<Status value={q.status}/>,can(account,'quotas.review')&&q.status==='PENDING'?<span className="actions"><button className="small" onClick={()=>decide(q,'APPROVED')}>Approve</button><button className="small danger" onClick={()=>decide(q,'DENIED')}>Deny</button></span>:'—'])}/>{show&&<Modal title="Submit quota activity" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label>Staff member<select name="staffProfileId" required><option value="">Select</option>{staff.map(s=><option value={s.id} key={s.id}>{s.displayName}</option>)}</select></label><label>Activity type<input name="activityType" required/></label><label>Points<input name="points" type="number" min="1" required/></label><label>Evidence link<input name="evidenceUrl" type="url"/></label><label className="wide">Description<textarea name="description" rows={4} required/></label><button className="wide">Submit activity</button></form></Modal>}</section>}

function Announcements(){const {account}=useAuth();const items=useDocs<Announcement>('announcements',[orderBy('createdAt','desc')]);const [show,setShow]=useState(false);async function create(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await addDoc(collection(db,'announcements'),{title:String(f.get('title')).trim(),body:String(f.get('body')).trim(),priority:String(f.get('priority')),audience:String(f.get('audience')).trim(),published:true,createdBy:auth.currentUser?.uid,createdAt:serverTimestamp()});setShow(false)}return <section><Section title="Announcements" subtitle="Targeted organization-wide communication" action={can(account,'announcements.manage')?<button onClick={()=>setShow(true)}><Plus/>New announcement</button>:undefined}/><div className="announcement-list">{items.filter(a=>a.published||can(account,'announcements.manage')).map(a=><article className={`announcement ${a.priority.toLowerCase()}`} key={a.id}><div><span className="badge">{a.priority}</span><small>{a.audience} · {date(a.createdAt)}</small></div><h2>{a.title}</h2><p>{a.body}</p>{can(account,'announcements.manage')&&<button className="small ghost-inline" onClick={()=>updateDoc(doc(db,'announcements',a.id),{published:!a.published})}>{a.published?'Unpublish':'Publish'}</button>}</article>)}</div>{show&&<Modal title="Publish announcement" onClose={()=>setShow(false)}><form onSubmit={create} className="form-grid"><label className="wide">Title<input name="title" required/></label><label>Priority<select name="priority"><option>NORMAL</option><option>IMPORTANT</option><option>URGENT</option></select></label><label>Audience<input name="audience" defaultValue="All Staff" required/></label><label className="wide">Message<textarea name="body" rows={7} required/></label><button className="wide">Publish announcement</button></form></Modal>}</section>}

function Admin(){const {account}=useAuth();if(!account?.systemRoles?.includes('SYSTEM_ADMINISTRATOR'))return <Navigate to="/dashboard"/>;return <section><Section title="System Administration" subtitle="Technical access and portal configuration"/><div className="grid"><Card title="Authentication" value="Active" text="Cross-device username and password access"/><Card title="Personnel Module" value="Online" text="Staff, ranks, quotas, and workflows"/><Card title="Next Module" value="Compliance" text="Discipline, appeals, alliances, applications"/></div><div className="panel"><KeyRound/><div><h2>Phase 2 deployed</h2><p>The connected staff and personnel operations foundation is ready for data entry and spreadsheet migration.</p></div></div></section>}
function Protected(){const {user,account,loading}=useAuth();if(loading)return <div className="loading">Loading Canela Portal…</div>;if(!user||!account||account.portalStatus!=='ACTIVE')return <Navigate to="/login"/>;return <Shell/>}
export default function App(){return <Routes><Route path="/login" element={<Login/>}/><Route path="/activate" element={<Activate/>}/><Route path="/*" element={<Protected/>}/></Routes>}
